import React, { useEffect, useState } from 'react';
import axios from 'axios';

const MyOrders = () => {
  const [orders, setOrders] = useState([]);
  var uid=localStorage.getItem("id",0);
  useEffect(() => {
    fetchOrders();
  }, [orders]);

  const fetchOrders = async () => {
    try {
      // Fetch orders from your backend API

      const response = await axios.get('http://localhost/Petshop/showorder.php?uid='+uid);
      setOrders(response.data);
    } catch (error) {
      console.error('Error fetching orders:', error);
    }
  };

  return (
    <div>
      <h2>My Orders</h2>
      <div className="orders-list">
        {orders.map(order => (
          <div key={order.oid} className="order-item">
            <h3>Order ID: {order.oid}</h3>
            <p>Order ID: {order.order_id}</p>
            <p>Total ITEM: {order.totalitem}</p>
            <p>Total Amount: {order.amount}</p>
            <ul>
              {order.items.map(item => (
                <li key={item.id}>

                </li>
              ))}
            </ul>
          </div>
        ))}
      </div>
    </div>
  );
};

export default MyOrders;
